<span class="line"><span style="color:#F8F8F2;">        dist </span><span style="color:#F92672;">=</span><span style="color:#66D9EF;font-style:italic;"> list</span><span style="color:#F8F8F2;">((((train.iloc[:, :n] </span><span style="color:#F92672;">-</span><span style="color:#F8F8F2;"> test.iloc[i, :n]) </span><span style="color:#F92672;">**</span><span style="color:#AE81FF;"> 2</span><span style="color:#F8F8F2;">).sum(</span><span style="color:#AE81FF;">1</span><span style="color:#F8F8F2;">))</span><span style="color:#F92672;">**</span><span style="color:#AE81FF;">5</span><span style="color:#F8F8F2;">)</span></span>
